/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 *
 * Design: Preferences are per-user with per-channel settings. Each channel
 * (email, SMS, webhook) has its own enabled flag and subscribed categories.
 * The PreferencesService provides defaults for users who haven't explicitly
 * set preferences.
 *
 * History: Originally designed with email as the only channel. Updated to
 * support per-channel preferences after SMS (Session 8) and webhook channels
 * were added. The email-only assumption is NO LONGER VALID — all notification
 * channels must be checked via their respective preference settings.
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': sent as they occur
 * - 'daily_digest': batched into a daily summary
 * - 'weekly_digest': batched into a weekly summary
 * - 'never': email notifications disabled via frequency
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest' | 'never';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * SMS-specific notification preferences.
 * SMS is always immediate (no digest support) and defaults to disabled
 * since it costs money and requires a phone number.
 */
export interface SmsPreferences {
  enabled: boolean;
  subscribedCategories: NotificationType[];
}

/**
 * Webhook-specific notification preferences.
 * Webhooks are always immediate and default to disabled.
 */
export interface WebhookPreferences {
  enabled: boolean;
  subscribedCategories: NotificationType[];
}

/**
 * Full user preferences record with per-channel settings.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional — only
 * provided fields are updated.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating SMS preferences. All fields optional.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating webhook preferences. All fields optional.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification categories a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'user_welcome',
  'user_updated',
];

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default SMS preferences for new users.
 * Disabled by default — SMS requires explicit opt-in since it costs money
 * and requires a valid phone number.
 */
export const DEFAULT_SMS_PREFERENCES: SmsPreferences = {
  enabled: false,
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default webhook preferences for new users.
 * Disabled by default — webhooks require explicit opt-in and configuration.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: false,
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

