/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import { DEFAULT_SMS_PREFERENCES, DEFAULT_WEBHOOK_PREFERENCES } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string),
      sms: record['sms']
        ? JSON.parse(record['sms'] as string)
        : { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [...DEFAULT_SMS_PREFERENCES.subscribedCategories] },
      webhook: record['webhook']
        ? JSON.parse(record['webhook'] as string)
        : { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories] },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      sms: JSON.stringify(entity.sms),
      webhook: JSON.stringify(entity.webhook),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Pure validation functions for notification preferences.
 *
 * These functions contain no side effects and no database calls.
 * They evaluate preference rules given a preferences object.
 */

import type { EmailPreferences, SmsPreferences, WebhookPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';

/**
 * Determine whether an email notification should be sent based on preferences.
 * Returns true if email is enabled, frequency is not 'never', and the
 * notification type is in the user's subscribed categories.
 */
export function shouldSendEmailNotification(
  prefs: EmailPreferences,
  notificationType: NotificationType,
): boolean {
  if (!prefs.enabled) {
    return false;
  }

  if (prefs.frequency === 'never') {
    return false;
  }

  if (!prefs.subscribedCategories.includes(notificationType)) {
    return false;
  }

  return true;
}

/**
 * Determine whether an SMS notification should be sent based on preferences.
 * Returns true if SMS is enabled and the notification type is in the
 * user's subscribed categories. SMS has no frequency/digest — always immediate.
 */
export function shouldSendSmsNotification(
  prefs: SmsPreferences,
  notificationType: NotificationType,
): boolean {
  if (!prefs.enabled) {
    return false;
  }

  if (!prefs.subscribedCategories.includes(notificationType)) {
    return false;
  }

  return true;
}

/**
 * Determine whether a webhook notification should be sent based on preferences.
 * Returns true if webhook is enabled and the notification type is in the
 * user's subscribed categories.
 */
export function shouldSendWebhookNotification(
  prefs: WebhookPreferences,
  notificationType: NotificationType,
): boolean {
  if (!prefs.enabled) {
    return false;
  }

  if (!prefs.subscribedCategories.includes(notificationType)) {
    return false;
  }

  return true;
}

/**
 * Preferences service — business logic for managing user notification preferences.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 *
 * Provides methods to get, create, and update user preferences across all
 * notification channels (email, SMS, webhook). When no preferences exist for
 * a user, returns sensible defaults.
 *
 * Used by NotificationService to check whether a notification should be
 * delivered to a given user on a specific channel.
 */

import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
} from '../models/user-preferences.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import { Logger } from '../utils/logger.js';
import {
  shouldSendEmailNotification,
  shouldSendSmsNotification,
  shouldSendWebhookNotification,
} from '../validators/preferences.validator.js';

let nextId = 1;

function generateId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns stored preferences if they exist,
   * otherwise returns defaults without persisting them.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`No preferences found for user ${userId}, returning defaults`);
    const now = new Date();
    return {
      id: '',
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories] },
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [...DEFAULT_SMS_PREFERENCES.subscribedCategories] },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories] },
      createdAt: now,
      updatedAt: now,
    };
  }

  /**
   * Ensure a preferences record exists for a user. Returns the existing
   * record or creates one with defaults.
   */
  private ensurePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    const now = new Date();
    const prefs: UserPreferences = {
      id: generateId(),
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories] },
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [...DEFAULT_SMS_PREFERENCES.subscribedCategories] },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories] },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    this.logger.info(`Created preferences ${prefs.id} for user ${userId}`);
    return prefs;
  }

  /**
   * Create or update email preferences for a user. If no preferences record
   * exists, one is created. Otherwise the existing record is updated.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
    this.logger.info(`Updating email preferences for user ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);

    if (existing) {
      const updatedEmail = {
        enabled: input.enabled ?? existing.email.enabled,
        frequency: input.frequency ?? existing.email.frequency,
        subscribedCategories: input.subscribedCategories ?? [...existing.email.subscribedCategories],
      };

      return this.preferencesRepository.update(existing.id, {
        email: updatedEmail,
        updatedAt: new Date(),
      });
    }

    // Create new preferences record with defaults for other channels
    const now = new Date();
    const prefs: UserPreferences = {
      id: generateId(),
      userId,
      email: {
        enabled: input.enabled ?? DEFAULT_EMAIL_PREFERENCES.enabled,
        frequency: input.frequency ?? DEFAULT_EMAIL_PREFERENCES.frequency,
        subscribedCategories: input.subscribedCategories ?? [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories],
      },
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [...DEFAULT_SMS_PREFERENCES.subscribedCategories] },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories] },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    this.logger.info(`Created preferences ${prefs.id} for user ${userId}`);
    return prefs;
  }

  /**
   * Create or update SMS preferences for a user.
   */
  updateSmsPreferences(userId: string, input: UpdateSmsPreferencesInput): UserPreferences {
    this.logger.info(`Updating SMS preferences for user ${userId}`);

    const prefs = this.ensurePreferences(userId);

    const updatedSms = {
      enabled: input.enabled ?? prefs.sms.enabled,
      subscribedCategories: input.subscribedCategories ?? [...prefs.sms.subscribedCategories],
    };

    return this.preferencesRepository.update(prefs.id, {
      sms: updatedSms,
      updatedAt: new Date(),
    });
  }

  /**
   * Create or update webhook preferences for a user.
   */
  updateWebhookPreferences(userId: string, input: UpdateWebhookPreferencesInput): UserPreferences {
    this.logger.info(`Updating webhook preferences for user ${userId}`);

    const prefs = this.ensurePreferences(userId);

    const updatedWebhook = {
      enabled: input.enabled ?? prefs.webhook.enabled,
      subscribedCategories: input.subscribedCategories ?? [...prefs.webhook.subscribedCategories],
    };

    return this.preferencesRepository.update(prefs.id, {
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });
  }

  /**
   * Check whether a notification should be sent to a user via email.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);
    const result = shouldSendEmailNotification(prefs.email, notificationType);

    if (!result) {
      this.logger.info(`Email notification ${notificationType} suppressed for user ${userId} due to preferences`);
    }

    return result;
  }

  /**
   * Check whether a notification should be sent to a user via SMS.
   */
  shouldSendSms(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);
    const result = shouldSendSmsNotification(prefs.sms, notificationType);

    if (!result) {
      this.logger.info(`SMS notification ${notificationType} suppressed for user ${userId} due to preferences`);
    }

    return result;
  }

  /**
   * Check whether a notification should be sent to a user via webhook.
   */
  shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);
    const result = shouldSendWebhookNotification(prefs.webhook, notificationType);

    if (!result) {
      this.logger.info(`Webhook notification ${notificationType} suppressed for user ${userId} due to preferences`);
    }

    return result;
  }
}

