    });

    it('should return false when frequency is never', () => {
      expect(shouldSendEmailNotification(makeEmailPrefs({ frequency: 'never' }), 'order_confirmation')).toBe(false);
    });

    it('should return false when notification type is not subscribed', () => {
      expect(
        shouldSendEmailNotification(makeEmailPrefs({ subscribedCategories: ['user_welcome'] }), 'order_confirmation'),
      ).toBe(false);
    });

    it('should return true for daily_digest frequency', () => {
      expect(shouldSendEmailNotification(makeEmailPrefs({ frequency: 'daily_digest' }), 'order_confirmation')).toBe(true);
    });

    it('should return true for weekly_digest frequency', () => {
      expect(shouldSendEmailNotification(makeEmailPrefs({ frequency: 'weekly_digest' }), 'order_confirmation')).toBe(true);
    });
  });

  describe('shouldSendSmsNotification', () => {
    it('should return true when SMS is enabled and type is subscribed', () => {
      expect(shouldSendSmsNotification(makeSmsPrefs(), 'order_confirmation')).toBe(true);
    });

    it('should return false when SMS is disabled', () => {
      expect(shouldSendSmsNotification(makeSmsPrefs({ enabled: false }), 'order_confirmation')).toBe(false);
    });

    it('should return false when notification type is not subscribed', () => {
      expect(
        shouldSendSmsNotification(makeSmsPrefs({ subscribedCategories: ['user_welcome'] }), 'order_confirmation'),
      ).toBe(false);
    });

    it('should return true for all subscribed categories', () => {
      const prefs = makeSmsPrefs({ subscribedCategories: ['order_confirmation', 'order_status_update'] });
      expect(shouldSendSmsNotification(prefs, 'order_confirmation')).toBe(true);
      expect(shouldSendSmsNotification(prefs, 'order_status_update')).toBe(true);
      expect(shouldSendSmsNotification(prefs, 'user_welcome')).toBe(false);
    });
  });

  describe('shouldSendWebhookNotification', () => {
    it('should return true when webhook is enabled and type is subscribed', () => {
