import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let preferencesRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    service = new PreferencesService(preferencesRepo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return defaults when no preferences exist', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'user_welcome',
        'user_updated',
      ]);
    });

    it('should return default SMS preferences (disabled) when no preferences exist', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'user_welcome',
        'user_updated',
      ]);
    });

    it('should return default webhook preferences (disabled) when no preferences exist', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'user_welcome',
        'user_updated',
      ]);
    });

    it('should return stored preferences when they exist', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.frequency).toBe('daily_digest');
      expect(prefs.id).toBe('pref-0001');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should create preferences on first update', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toHaveLength(4);
    });

    it('should include default SMS and webhook preferences on creation', () => {
      const prefs = service.updateEmailPreferences('user-1', {});

      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.webhook.enabled).toBe(false);
    });

    it('should update existing preferences', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly_digest',
      });

      expect(updated.id).toBe('pref-0001');
      expect(updated.email.frequency).toBe('weekly_digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update subscribed categories', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(prefs.email.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should preserve unchanged fields on update', () => {
      service.updateEmailPreferences('user-1', {
        enabled: true,
        frequency: 'daily_digest',
        subscribedCategories: ['order_confirmation', 'order_status_update'],
      });

      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly_digest',
      });

      expect(updated.email.enabled).toBe(true);
      expect(updated.email.frequency).toBe('weekly_digest');
      expect(updated.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
      ]);
    });

    it('should generate sequential IDs for different users', () => {
      const prefs1 = service.updateEmailPreferences('user-1', {});
      const prefs2 = service.updateEmailPreferences('user-2', {});

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('updateSmsPreferences', () => {
    it('should enable SMS for a user', () => {
      const prefs = service.updateSmsPreferences('user-1', { enabled: true });

      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.subscribedCategories).toHaveLength(4);
    });

    it('should create preferences record if none exists', () => {
      const prefs = service.updateSmsPreferences('user-1', { enabled: true });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true); // email defaults preserved
    });

    it('should update SMS subscribed categories', () => {
      const prefs = service.updateSmsPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order_confirmation'],
      });

      expect(prefs.sms.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should preserve other channel preferences when updating SMS', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });
      const updated = service.updateSmsPreferences('user-1', { enabled: true });

      expect(updated.email.frequency).toBe('daily_digest');
    });

    it('should preserve unchanged SMS fields on update', () => {
      service.updateSmsPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order_confirmation', 'order_status_update'],
      });

      const updated = service.updateSmsPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(updated.sms.enabled).toBe(true);
      expect(updated.sms.subscribedCategories).toEqual(['order_confirmation']);
    });
  });

  describe('updateWebhookPreferences', () => {
    it('should enable webhook for a user', () => {
      const prefs = service.updateWebhookPreferences('user-1', { enabled: true });

      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.subscribedCategories).toHaveLength(4);
    });

    it('should create preferences record if none exists', () => {
      const prefs = service.updateWebhookPreferences('user-1', { enabled: true });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true); // email defaults preserved
      expect(prefs.sms.enabled).toBe(false);   // SMS defaults preserved
    });

    it('should update webhook subscribed categories', () => {
      const prefs = service.updateWebhookPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order_status_update'],
      });

      expect(prefs.webhook.subscribedCategories).toEqual(['order_status_update']);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true with default preferences', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when frequency is never', () => {
      service.updateEmailPreferences('user-1', { frequency: 'never' });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_status_update'],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(true);
    });

    it('should return true for subscribed categories with non-immediate frequency', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });
  });

  describe('shouldSendSms', () => {
    it('should return false with default preferences (SMS disabled by default)', () => {
      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return true when SMS is explicitly enabled', () => {
      service.updateSmsPreferences('user-1', { enabled: true });

      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when SMS category is not subscribed', () => {
      service.updateSmsPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order_status_update'],
      });

      expect(service.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendSms('user-1', 'order_status_update')).toBe(true);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return false with default preferences (webhook disabled by default)', () => {
      expect(service.shouldSendWebhook('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return true when webhook is explicitly enabled', () => {
      service.updateWebhookPreferences('user-1', { enabled: true });

      expect(service.shouldSendWebhook('user-1', 'order_confirmation')).toBe(true);
    });
  });
});

describe('NotificationService with preferences', () => {
  let eventBus: EventBus;
  let db: Database;
  let preferencesRepo: PreferencesRepository;
  let preferencesService: PreferencesService;
  let notificationService: NotificationService;
  let emailAdapter: EmailAdapter;

  function makeOrderCreatedEvent(userId: string, email: string): OrderCreatedEvent {
    return {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId,
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: userId,
        name: 'Test User',
        email,
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };
  }

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService = new NotificationService(eventBus, preferencesService);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should send notification when user has default preferences', async () => {
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    expect(notificationService.getNotifications()).toHaveLength(1);
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should suppress notification when email is disabled', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    expect(notificationService.getNotifications()).toHaveLength(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notification when category is unsubscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order_status_update'],
    });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    expect(notificationService.getNotifications()).toHaveLength(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notification when frequency is never', async () => {
    preferencesService.updateEmailPreferences('user-1', { frequency: 'never' });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    expect(notificationService.getNotifications()).toHaveLength(0);
  });

  it('should send notification when category is subscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order_confirmation'],
    });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    expect(notificationService.getNotifications()).toHaveLength(1);
  });

  it('should handle different preferences for different users', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });
    // user-2 keeps defaults (all enabled)

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    await eventBus.emit(makeOrderCreatedEvent('user-2', 'bob@example.com'));

    expect(notificationService.getNotifications()).toHaveLength(1);
    expect(notificationService.getNotificationsForRecipient('bob@example.com')).toHaveLength(1);
    expect(notificationService.getNotificationsForRecipient('alice@example.com')).toHaveLength(0);
  });
});

describe('NotificationService with SMS preferences', () => {
  let eventBus: EventBus;
  let db: Database;
  let preferencesRepo: PreferencesRepository;
  let preferencesService: PreferencesService;
  let notificationService: NotificationService;
  let smsAdapter: SmsAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService = new NotificationService(eventBus, preferencesService);
    smsAdapter = new SmsAdapter();
    notificationService.registerAdapter(smsAdapter);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should suppress SMS when SMS preferences are default (disabled)', async () => {
    // Manually dispatch an SMS notification by triggering via the internal flow
    // SMS is disabled by default, so it should be suppressed
    // We need to go through a public API, so let's check via shouldSendSms
    expect(preferencesService.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
  });

  it('should allow SMS when user has opted in', async () => {
    preferencesService.updateSmsPreferences('user-1', { enabled: true });

    expect(preferencesService.shouldSendSms('user-1', 'order_confirmation')).toBe(true);
  });

  it('should suppress SMS for unsubscribed categories', async () => {
    preferencesService.updateSmsPreferences('user-1', {
      enabled: true,
      subscribedCategories: ['order_status_update'],
    });

    expect(preferencesService.shouldSendSms('user-1', 'order_confirmation')).toBe(false);
    expect(preferencesService.shouldSendSms('user-1', 'order_status_update')).toBe(true);
  });
});

